// Login Page Class
// Generated by Qentrix for AG-Helix

import BasePage from './basePage.js';
import { expect } from '@playwright/test';
import * as loginPageSelectors from '../pageObjects/loginPage.js';

export default class LoginPage extends BasePage {
    constructor(page) {
        super(page);
    }

    /**
     * Navigate to login page
     */
    async navigateToLoginPage(url = process.env.BASE_URL) {
        await this.open(url || 'http://192.168.10.124:4001');
        await super.waitForPageLoad();
    }

    /**
     * Verify login page is displayed
     */
    async verifyLoginPageDisplayed() {
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.usernameInput).first()).toBeVisible({ timeout: 10000 });
        await expect(this.page.locator(loginPageSelectors.passwordInput).first()).toBeVisible();
        await expect(this.page.locator(loginPageSelectors.loginButton).first()).toBeVisible();
    }

    /**
     * Verify all login page elements are present
     */
    async verifyAllLoginPageElements() {
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.usernameInput).first()).toBeVisible();
        await expect(this.page.locator(loginPageSelectors.passwordInput).first()).toBeVisible();
        await expect(this.page.locator(loginPageSelectors.loginButton).first()).toBeVisible();
        const registerLinkCount = await this.getCount(loginPageSelectors.registerLink);
        if (registerLinkCount > 0) {
            await expect(this.page.locator(loginPageSelectors.registerLink).first()).toBeVisible();
        }
    }

    /**
     * Enter username
     */
    async enterUsername(username) {
        await this.waitAndFill(loginPageSelectors.usernameInput, username);
    }

    /**
     * Enter password
     */
    async enterPassword(password) {
        await this.waitAndFill(loginPageSelectors.passwordInput, password);
    }

    /**
     * Enter credentials (username and password)
     */
    async enterCredentials(username, password) {
        await this.enterUsername(username);
        await this.enterPassword(password);
    }

    /**
     * Enter valid credentials from test data
     */
    async enterValidCredentials(role = 'Admin') {
        const credentials = this.getLoginDataByRole(role);
        await this.enterUsername(credentials.username);
        await this.enterPassword(credentials.password);
    }

    /**
     * Enter username with special characters
     */
    async enterUsernameWithSpecialCharacters(username = 'test@#$%user') {
        await this.enterUsername(username);
    }

    /**
     * Enter username with unicode characters
     */
    async enterUsernameWithUnicodeCharacters(username = 'testユーザー名') {
        await this.enterUsername(username);
    }

    /**
     * Enter password with unicode characters
     */
    async enterPasswordWithUnicodeCharacters(password = 'パスワード123') {
        await this.enterPassword(password);
    }

    /**
     * Enter maximum length username
     */
    async enterMaximumLengthUsername(length = 255) {
        const maxUsername = 'a'.repeat(length);
        await this.enterUsername(maxUsername);
    }

    /**
     * Enter maximum length password
     */
    async enterMaximumLengthPassword(length = 255) {
        const maxPassword = 'P@ssw0rd' + 'a'.repeat(length - 8);
        await this.enterPassword(maxPassword);
    }

    /**
     * Enter credentials with whitespace
     */
    async enterCredentialsWithWhitespace(username = '  testuser  ', password = '  password  ') {
        await this.enterUsername(username);
        await this.enterPassword(password);
    }

    /**
     * Enter SQL injection string in username
     */
    async enterSQLInjectionUsername(sqlString = "admin' OR '1'='1") {
        await this.enterUsername(sqlString);
    }

    /**
     * Leave username field empty
     */
    async leaveUsernameEmpty() {
        await this.page.locator(loginPageSelectors.usernameInput).first().clear();
    }

    /**
     * Leave password field empty
     */
    async leavePasswordEmpty() {
        await this.page.locator(loginPageSelectors.passwordInput).first().clear();
    }

    /**
     * Click login button
     */
    async clickLoginButton() {
        await this.waitAndClick(loginPageSelectors.loginButton);
        await super.waitforNetworkIdle();
    }

    /**
     * Click login button multiple times rapidly
     */
    async clickLoginButtonRapidly(times = 5) {
        for (let i = 0; i < times; i++) {
            await this.page.locator(loginPageSelectors.loginButton).first().click({ timeout: 1000 }).catch(() => {});
        }
        await this.page.waitForTimeout(500);
    }

    /**
     * Press tab key
     */
    async pressTabKey() {
        await this.page.keyboard.press('Tab');
    }

    /**
     * Press enter key
     */
    async pressEnterKey() {
        await this.page.keyboard.press('Enter');
        await super.waitforNetworkIdle();
    }

    /**
     * Verify error message is displayed
     */
    async verifyErrorMessageDisplayed() {
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.errorMessage).first()).toBeVisible({ timeout: 10000 });
    }

    /**
     * Verify specific error message
     */
    async verifySpecificErrorMessage(expectedMessage) {
        await this.wait();
        const errorLocator = this.page.locator(loginPageSelectors.errorMessage).first();
        await expect(errorLocator).toBeVisible();
        await this.verifyElementContainsText(loginPageSelectors.errorMessage, expectedMessage);
    }

    /**
     * Verify username required error
     */
    async verifyUsernameRequiredError() {
        await this.wait();
        const errorCount = await this.getCount(loginPageSelectors.usernameRequiredError);
        if (errorCount > 0) {
            await expect(this.page.locator(loginPageSelectors.usernameRequiredError).first()).toBeVisible();
        } else {
            await expect(this.page.locator(loginPageSelectors.errorMessage).first()).toBeVisible();
        }
    }

    /**
     * Verify password required error
     */
    async verifyPasswordRequiredError() {
        await this.wait();
        const errorCount = await this.getCount(loginPageSelectors.passwordRequiredError);
        if (errorCount > 0) {
            await expect(this.page.locator(loginPageSelectors.passwordRequiredError).first()).toBeVisible();
        } else {
            await expect(this.page.locator(loginPageSelectors.errorMessage).first()).toBeVisible();
        }
    }

    /**
     * Verify account disabled error
     */
    async verifyAccountDisabledError() {
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.accountDisabledError).first()).toBeVisible({ timeout: 10000 });
    }

    /**
     * Verify rate limiting message
     */
    async verifyRateLimitingMessage() {
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.rateLimitError).first()).toBeVisible({ timeout: 10000 });
    }

    /**
     * Verify user remains on login page
     */
    async verifyUserRemainsOnLoginPage() {
        await this.wait();
        const currentUrl = await this.getUrl();
        expect(currentUrl).toContain('login');
        await expect(this.page.locator(loginPageSelectors.loginButton).first()).toBeVisible();
    }

    /**
     * Verify successful login (user navigated away from login page)
     */
    async verifySuccessfulLogin() {
        await this.wait(3000);
        const currentUrl = await this.getUrl();
        expect(currentUrl).not.toContain('login');
    }

    /**
     * Verify password field masks input
     */
    async verifyPasswordFieldMasked() {
        await this.wait();
        const passwordField = this.page.locator(loginPageSelectors.passwordInput).first();
        const inputType = await passwordField.getAttribute('type');
        expect(inputType).toBe('password');
    }

    /**
     * Verify HTTPS protocol is used
     */
    async verifyHTTPSProtocol() {
        await this.wait();
        const currentUrl = await this.getUrl();
        expect(currentUrl).toMatch(/^https:\/\//);
    }

    /**
     * Verify placeholder text in username field
     */
    async verifyUsernamePlaceholder() {
        await this.wait();
        const usernameField = this.page.locator(loginPageSelectors.usernameInput).first();
        const placeholder = await usernameField.getAttribute('placeholder');
        expect(placeholder).toBeTruthy();
    }

    /**
     * Verify placeholder text in password field
     */
    async verifyPasswordPlaceholder() {
        await this.wait();
        const passwordField = this.page.locator(loginPageSelectors.passwordInput).first();
        const placeholder = await passwordField.getAttribute('placeholder');
        expect(placeholder).toBeTruthy();
    }

    /**
     * Verify login button is clickable
     */
    async verifyLoginButtonClickable() {
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.loginButton).first()).toBeEnabled();
    }

    /**
     * Verify login button hover state
     */
    async verifyLoginButtonHoverState() {
        await this.wait();
        await this.page.locator(loginPageSelectors.loginButton).first().hover();
        await this.page.waitForTimeout(500);
    }

    /**
     * Verify page load time is acceptable
     */
    async verifyPageLoadTime(maxLoadTime = 3000) {
        const startTime = Date.now();
        await this.page.waitForLoadState('domcontentloaded');
        const loadTime = Date.now() - startTime;
        expect(loadTime).toBeLessThan(maxLoadTime);
    }

    /**
     * Verify login response time
     */
    async verifyLoginResponseTime(maxResponseTime = 2000) {
        const startTime = Date.now();
        await this.clickLoginButton();
        const responseTime = Date.now() - startTime;
        expect(responseTime).toBeLessThan(maxResponseTime);
    }

    /**
     * Verify responsive design on different screen sizes
     */
    async verifyResponsiveDesign(width, height) {
        await this.page.setViewportSize({ width, height });
        await this.wait();
        await expect(this.page.locator(loginPageSelectors.usernameInput).first()).toBeVisible();
        await expect(this.page.locator(loginPageSelectors.passwordInput).first()).toBeVisible();
        await expect(this.page.locator(loginPageSelectors.loginButton).first()).toBeVisible();
    }

    /**
     * Verify field validation styling
     */
    async verifyFieldValidationStyling() {
        await this.wait();
        const usernameField = this.page.locator(loginPageSelectors.usernameInput).first();
        await usernameField.fill('invalid');
        await this.page.locator(loginPageSelectors.passwordInput).first().click();
        await this.wait(500);
        // Check for validation styling classes or aria-invalid attribute
        const ariaInvalid = await usernameField.getAttribute('aria-invalid');
        const hasErrorClass = await usernameField.evaluate(el => {
            return el.classList.contains('error') || el.classList.contains('is-invalid');
        });
        expect(ariaInvalid === 'true' || hasErrorClass).toBeTruthy();
    }

    /**
     * Focus on username field
     */
    async focusUsernameField() {
        await this.page.locator(loginPageSelectors.usernameInput).first().click();
    }

    /**
     * Focus on password field
     */
    async focusPasswordField() {
        await this.page.locator(loginPageSelectors.passwordInput).first().click();
    }

    /**
     * Navigate away from page
     */
    async navigateAway() {
        await this.page.goto('about:blank');
    }

    /**
     * Navigate back to login page
     */
    async navigateBackToLogin() {
        await this.page.goBack();
        await super.waitForPageLoad();
    }

    /**
     * Clear browser cache
     */
    async clearBrowserCache() {
        await this.page.context().clearCookies();
    }

    /**
     * Monitor API request format
     */
    async monitorAPIRequest() {
        return new Promise((resolve) => {
            this.page.once('request', request => {
                if (request.url().includes('login') || request.url().includes('auth')) {
                    resolve({
                        url: request.url(),
                        method: request.method(),
                        postData: request.postData(),
                        headers: request.headers()
                    });
                }
            });
        });
    }
}

